"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[3269],{1957:e=>{e.exports=JSON.parse('{"version":{"pluginId":"detections","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"detectionsSidebar":[{"type":"category","label":"Detection Techniques","items":[{"type":"link","href":"/MariOT_Matrix/detections/","label":"Introduction","docId":"index","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/authentication_logs","label":"Authentication Logs","docId":"authentication_logs","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/network_traffic_logs","label":"Network Traffic Logs","docId":"network_traffic_logs","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/endpoint_detection_and_response","label":"Endpoint Detection and Response","docId":"endpoint_detection_and_response","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/file_access_and_modification_logs","label":"File Access & Modification Logs","docId":"file_access_and_modification_logs","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/control_logic_changes","label":"Control Logic Changes","docId":"control_logic_changes","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/engineering_workstation_actions","label":"Engineering Workstation Actions","docId":"engineering_workstation_actions","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/process_variable_logs","label":"Process Variable Logs","docId":"process_variable_logs","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/serial_communication","label":"Serial Communication Logs","docId":"serial_communication","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/firmware_update_logs","label":"Firmware update logs","docId":"firmware_update_logs","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/device_status_and_diagnostics","label":"Device status and diagnostics logs","docId":"device_status_and_diagnostics","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/hmi_interaction_logs","label":"HMI interaction logs","docId":"hmi_interaction_logs","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/time_synchronization_logs","label":"Time synchronization logs","docId":"time_synchronization_logs","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/physical_port_access_logs","label":"Physical port access logs","docId":"physical_port_access_logs","unlisted":false},{"type":"link","href":"/MariOT_Matrix/detections/alarm_and_event_logs","label":"Alarm and event logs","docId":"alarm_and_event_logs","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"alarm_and_event_logs":{"id":"alarm_and_event_logs","title":"Alarm and event logs","description":"Alarm and event logs record system-generated alerts and operator acknowledgments related to safety, control anomalies, sensor errors, and communication failures. These logs are integral to the vessel monitoring systems and provide insight into how the vessel responds to unexpected behaviors ,.","sidebar":"detectionsSidebar"},"authentication_logs":{"id":"authentication_logs","title":"Authentication Logs","description":"Authentication logs in maritime environments OT record user access and identity verification activities in critical operational components, such as engineering workstations, HMI terminals and remote access gateways, including those employing satellite links (e.g., VSAT) . Each log entry typically includes metadata such as timestamp, source IP address, authentication method, and the privilege level associated with the account involved.","sidebar":"detectionsSidebar"},"control_logic_changes":{"id":"control_logic_changes","title":"Control Logic Changes","description":"Control logic change logs record modifications to automation programs and control sequences implemented on ships\u2019 operating technology devices, including PLC, remote terminal units (RTUs), and propulsion control modules. In maritime contexts, these changes can influence essential operations such as the regulation of engine thrust, ballast system automation, and electrical power distribution . These logs track events related to the upload, download, editing, and activation of control logic. Modifications can originate from engineering stations on board or remote access sessions established through maintenance interfaces .","sidebar":"detectionsSidebar"},"device_status_and_diagnostics":{"id":"device_status_and_diagnostics","title":"Device status and diagnostics logs","description":"Device status and diagnostics logs in maritime OT environments record operational states, internal diagnostics, and performance indicators of shipboard control and monitoring systems. Typical sources include PLC units, HMI terminals, power management modules, and propulsion controllers. These logs include entries related to system restarts, diagnostic fault codes, watchdog timer activations, and transitions between operating modes, including changes from automatic to manual control .","sidebar":"detectionsSidebar"},"endpoint_detection_and_response":{"id":"endpoint_detection_and_response","title":"Endpoint Detection and Response","description":"Endpoint Detection and Response (EDR) refers to a cybersecurity solution designed to monitor, detect, and respond to threats on endpoint devices, including shipboard workstations, control servers, human-machine interfaces (HMIs), and industrial control systems. In maritime OT environments, EDR is critical for detecting anomalous behavior on propulsion management consoles, navigation terminals, and vendor-managed remote access platforms.","sidebar":"detectionsSidebar"},"engineering_workstation_actions":{"id":"engineering_workstation_actions","title":"Engineering Workstation Actions","description":"Engineering workstation action logs document user activities on board EWS, which function as centralized interfaces to configure, update, and manage operational technology assets such as PLC, HMI and navigation control systems. In maritime OT environments, these logs include events such as downloads of control logic to propulsion units, parameter modifications in automation routines, firmware deployment actions, and access to remote terminal sessions.","sidebar":"detectionsSidebar"},"file_access_and_modification_logs":{"id":"file_access_and_modification_logs","title":"File Access & Modification Logs","description":"File Access and Modification Logs are critical components of security monitoring within shipboard systems, recording changes to files, directories, and executable content. In maritime OT environments, such logs are essential for tracking unauthorized modifications in propulsion control units, navigation systems such as ECDIS, and remote maintenance interfaces accessed by external vendors or classification societies . These logs are particularly valuable for identifying persistent advanced threats, manipulation of control logic, and configuration changes outside of approved operational procedures .","sidebar":"detectionsSidebar"},"firmware_update_logs":{"id":"firmware_update_logs","title":"Firmware update logs","description":"Firmware update logs in maritime environments OT document events associated with the modification, replacement, or reinstallation of firmware on critical shipboard components. The affected devices include PLC, HMI, propulsion control units, and sensor interface modules. These logs typically contain metadata such as firmware version identifiers, update timestamps, the origin of the update (e.g., onboard technician or remote vendor) and the corresponding delivery channel. Due to the extended operational lifespan of maritime systems and the frequent use of remote maintenance through VSAT or vendor-managed links , firmware updates constitute a potential attack surface with implications for both device functionality and system security .","sidebar":"detectionsSidebar"},"hmi_interaction_logs":{"id":"hmi_interaction_logs","title":"HMI interaction logs","description":"HMI interaction logs record operator actions performed via onboard interfaces, such as charting software, bridge displays, or SCADA terminals. These logs capture button presses, screen navigation events, manual overrides, and parameter adjustments initiated by crew members .","sidebar":"detectionsSidebar"},"index":{"id":"index","title":"Detection Overview","description":"Welcome to the Detection Techniques documentation. This section provides insights into different data sources and detection strategies.","sidebar":"detectionsSidebar"},"network_traffic_logs":{"id":"network_traffic_logs","title":"Network Traffic Logs","description":"Network traffic logs  document data exchange between the IT and OT systems. In maritime environments, these logs encompass conventional protocols, including HTTP, DNS, email and file transfer, in addition to industrial and maritime-specific communication standards such as Modbus/TCP, NMEA 0183, IEC 61162, and proprietary telemetry used in navigation, propulsion, and power control systems. Traffic records may be stored in summarized formats (e.g., NetFlow) or captured as raw packet traces (e.g., PCAP) to support detailed forensic investigations . These logs are essential for identifying anomalies, including unauthorized remote access, exploitation of encrypted communication channels, and manipulation of control layer protocols. Within maritime OT infrastructures, continuous monitoring of network traffic is fundamental for detecting remote maintenance interface abuse, lateral movement through trusted industrial protocols, and improper use of vendor-provided VPN connections and administrative access tools operating over satellite links such as VSAT or Iridium.","sidebar":"detectionsSidebar"},"physical_port_access_logs":{"id":"physical_port_access_logs","title":"Physical port access logs","description":"Physical port access logs monitor interactions with onboard data interfaces, including USB ports, serial connectors, and RJ45 Ethernet jacks. These logs capture device insertion/removal events, port activation, and data flow initiation from external sources .","sidebar":"detectionsSidebar"},"process_variable_logs":{"id":"process_variable_logs","title":"Process Variable Logs","description":"Process variable logs in maritime OT environments store time series data generated by sensors and control systems that monitor the physical state of shipboard operations. These logs contain measurements related to engine Revolutions Per Minute (RPM), shaft torque, fuel pressure, ballast tank levels, electrical load and environmental metrics, including temperature, humidity, and CO2 concentration. Data are acquired from PLC devices, data acquisition modules, or the PMS infrastructure.","sidebar":"detectionsSidebar"},"serial_communication":{"id":"serial_communication","title":"Serial Communication Logs","description":"Serial communication logs in maritime environments OT record data exchanged over legacy serial interfaces that are still widely used in shipboard systems. These logs capture protocol-level traffic based on standards such as NMEA 0183, Modbus RTUs, and IEC 61162-1/2. Such protocols are commonly implemented on devices including GPS receivers, AIS transponders, engine governors, and autopilot controllers. Serial links are typically used for navigation support, propulsion system monitoring, and sensor integration. Their continued use is attributed to the simplicity of architectural design and the long-established reliability in deterministic maritime operations.","sidebar":"detectionsSidebar"},"time_synchronization_logs":{"id":"time_synchronization_logs","title":"Time synchronization logs","description":"Time synchronization logs track the timing alignment of various shipboard subsystems, such as navigation controllers, radar systems, and data loggers. These records include NTP synchronization events, manual time adjustments, and drift correction statistics .","sidebar":"detectionsSidebar"}}}}')}}]);